    __CPROVER_is_fresh(lz77->ll_counts,
        ((size_t)ZOPFLI_NUM_LL * ((lend - 1) / ZOPFLI_NUM_LL) + ZOPFLI_NUM_LL)
            * sizeof(*lz77->ll_counts)))
