    __CPROVER_is_fresh(lz77->d_counts,
        ((size_t)ZOPFLI_NUM_D * ((lend - 1) / ZOPFLI_NUM_D) + ZOPFLI_NUM_D)
            * sizeof(*lz77->d_counts)))
