    size_t jl; (lstart + ZOPFLI_NUM_LL * 3 > lend && lstart <= jl && jl < lend)
                  ==> (lz77->litlens[jl] < 259)
})
__CPROVER_requires(__CPROVER_forall {
    size_t jr; (lstart + ZOPFLI_NUM_LL * 3 > lend
                && lstart <= jr && jr < lend && lz77->dists[jr] != 0)
                  ==> (lz77->litlens[jr] >= 3
                       && lz77->dists[jr] >= 1 && lz77->dists[jr] <= 32768)
})
